var N0_FINAL = 400;
var N0_INTERACTIVO = 200;
var PROF_MAX_FINAL = 20;
var PROF_MAX_INTERACTIVO = 14;
var SALTO_PX_FINAL = 10;
var SALTO_PX_INTERACTIVO = 16;
var MAX_EVALS_FINAL2 = 3e5;
var MAX_EVALS_INTERACTIVO2 = 1e5;
